library(shiny)
library(reactable)
library(dplyr)


# To transfer the needed documents, use the following command in the terminal:
#shinylive::export(appdir = "../CARI_sumTables/", destdir = "docs")

cari_sums <- readRDS("cari_sums.rds")

ui <- fluidPage(
  h2("Canadian Accessibility and Remoteness Index - Classification Summaries", align = "centre"),

  fluidRow(
    column(4,
      selectInput("CARI_version", "CARI Version:",
                  choices = c("Emergency Departments" = "ED",
                              "High Schools" = "HS",
                              "Birth Services" = "OB",
                              "Population Centres" = "PP",
                              "NDD Health Services (Ontario)" = "ND",
                              "Pharmacies (Ontario)" = "PH"),
                  selected = "ED")
    ),
    column(4,
      selectInput("Method", "Categorization Method:",
                  choices = c("Jenks - Distance" = "Jenks - Distance",
                              "Jenks - Minutes" = "Jenks - Minutes",
                              "Std. Dev. - Distance" = "Std. Dev. - Distance",
                              "Std. Dev. - Minutes" = "Std. Dev. - Minutes",
                              "Quantile - Distance" = "Quantile - Distance",
                              "Quantile - Minutes" = "Quantile - Minutes"),
                  selected = "Jenks - Distance")
    )
  ),

  reactableOutput("table")
)

server <- function(input, output) {

  selected_data <- reactive({
    cari_sums %>%
      filter(CARI_Version == input$CARI_version,
             Method == input$Method)
  })

  output$table <- renderReactable({

    df <- selected_data()
    df <- df %>%
      mutate(Category = case_when(
        Indicator == "Total Population" ~ "Population",
        Indicator %in% c("Males", "Females") ~ "Sex",
        Indicator %in% c("<15 years", "15-64 years", "65+") ~ "Age Structure",
        Indicator %in% c("Less than HS", "High School", 
                         "Diploma", "University") ~ "Education",
        Indicator %in% c("Immigrants", "Non-Immigrants", 
                         "Imm. (<10yrs)") ~ "Immigration",
        Indicator %in% c("Indigenous", "Non-Indigenous") ~ "Indigenous Identity",
        Indicator %in% c("Material", "Social") ~ "Deprivation",
        Indicator %in% c("Instability", "Dependency", 
                         "Ethnic Conc.", "Deprivation") ~ "Marginalization",

        TRUE ~ "Other"
      )) %>%
      select(Category, Indicator, cat1, cat2, cat3, cat4, cat5)

    reactable(
      df,
      defaultPageSize = 21,
      compact = TRUE, height = "auto", outlined = TRUE,
      columns = list(
        Category = colDef(name = "Category",
                        style = JS("function(rowInfo, column, state) {
        const firstSorted = state.sorted[0]
        // Merge cells if unsorted or sorting by school
        if (!firstSorted || firstSorted.id === 'Category') {
          const prevRow = state.pageRows[rowInfo.viewIndex - 1]
          if (prevRow && rowInfo.values['Category'] === prevRow['Category']) {
            return { visibility: 'hidden' }
          }
        }
      }"),
                        html = TRUE, # Must be TRUE to render the span tag
                        cell = JS("
        function(cellInfo) {
          let tooltipText = '';
          // Logic for specific value cases
          if (cellInfo.value === 'Deprivation') {
            tooltipText = 'Shows the population-weighted mean for the Material and Social Deprivation Index (INSPQ)';
          } else if (cellInfo.value === 'Marginalization') {
            tooltipText = 'Shows the population-weighted mean for the Canadian Marginalization Index (Statistics Canada)';
          }
          // If a tooltip text was set, wrap the value in a span
          if (tooltipText !== '') {
            return `<span title='${tooltipText}' style='cursor: help; border-bottom: 1px dotted;'>${cellInfo.value}</span>`
          }
          // Otherwise, return the value as a plain string (no tooltip)
          return cellInfo.value
        }
      ")
                        ),
        Indicator = colDef(name = "Indicator"),
        cat1 = colDef(name = "Easily Accessible", cell = function(value) {
          if (value > 100) {formatted_value <- format(value, big.mark = ",") }
          else if (value < 1) {formatted_value <- sprintf("%.2f", value) }
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat2 = colDef(name = "Accessible", cell = function(value) {
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else if (value < 1) {formatted_value <- sprintf("%.2f", value) }
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat3 = colDef(name = "Less Accessible", cell = function(value) {
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else if (value < 1) {formatted_value <- sprintf("%.2f", value) }
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat4 = colDef(name = "Remote", cell = function(value) {
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else if (value < 1) {formatted_value <- sprintf("%.2f", value) }
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat5 = colDef(name = "More Remote", cell = function(value) {
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else if (value < 1) {formatted_value <- sprintf("%.2f", value) }
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) })
      ),
      ,
      rowStyle = JS("function(rowInfo) {
    if (rowInfo.level > 0) {
      return { background: '#eee', borderLeft: '2px solid #ffa62d' }
    } else {
      return { borderLeft: '2px solid transparent' }
    }
  }")
    )

  })

}

shinyApp(ui, server)
